customCSS:
/* Compact Minimal Theme */

/* Reduce overall padding */
.dashboard-content {
  padding: 1rem;
}

.dashboard-header {
  padding: 0.75rem 1rem;
}

/* Smaller header */
.logo {
  font-size: 1.2rem;
}

.header-right {
  gap: 0.5rem;
}

.refresh-btn {
  padding: 0.4rem 0.75rem;
  font-size: 0.8rem;
}

/* Compact stats grid */
.stats-overview {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.stat-card {
  padding: 0.75rem;
  border-radius: 8px;
}

.stat-label {
  font-size: 0.65rem;
  margin-bottom: 0.25rem;
}

.stat-value {
  font-size: 1.3rem;
}

.stat-unit {
  font-size: 0.75rem;
}

.stat-sub {
  font-size: 0.7rem;
  margin-top: 0.15rem;
}

/* Section headers smaller */
.section-header {
  margin-bottom: 0.5rem;
}

.section-header h2 {
  font-size: 1rem;
}

/* Compact miner grid */
.miners-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 0.75rem;
}

/* Compact miner cards */
.miner-card {
  border-radius: 8px;
}

.miner-header {
  padding: 0.5rem 0.75rem;
}

.miner-name {
  font-size: 0.9rem;
}

.miner-type {
  font-size: 0.65rem;
  padding: 0.15rem 0.4rem;
}

.miner-body {
  padding: 0.75rem;
}

/* Single row stats in compact mode */
.compact-mode .miner-stats {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.compact-mode .miner-stat {
  flex: 1 1 45%;
  padding: 0.5rem;
  min-width: 80px;
}

.compact-mode .miner-stat-label {
  font-size: 0.6rem;
}

.compact-mode .miner-stat-value {
  font-size: 0.9rem;
}

/* Compact temperature gauge */
.compact-mode .temp-gauge {
  display: none;
}

/* Minimal footer */
.dashboard-footer {
  padding: 0.75rem 1rem;
}

.footer-info {
  font-size: 0.75rem;
}

/* Hide decorative elements */
.cyber-grid,
.cyber-glow,
.cyber-particles {
  opacity: 0.3;
}

/* Mobile-first responsive adjustments already built in */
@media (max-width: 600px) {
  .stats-overview {
    grid-template-columns: repeat(2, 1fr);
  }

  .miners-grid {
    grid-template-columns: 1fr;
  }
}

/* Perfect for sidebar or small window */
@media (max-width: 400px) {
  .dashboard-content {
    padding: 0.5rem;
  }

  .stat-card {
    padding: 0.5rem;
  }

  .stat-value {
    font-size: 1.1rem;
  }
}
